Bash(powershell -Command "
\\$downloadDir = Join-Path \\$env:USERPROFILE 'Downloads'
\\$files = Get-ChildItem \\$downloadDir -Filter '*.png' | Where-Object { \\$_.Name -notmatch '屏幕截图|Image_|~' }
\\$repoRoot = 'D:\\aMyGameSelf\\ModMaker\\CharacterModTemplate'
\\$zhCardsPath = Join-Path \\$repoRoot 'CharMod\\localization\\zh\\cards.json'
\\$zhCards = Get-Content \\$zhCardsPath -Raw -Encoding UTF8 | ConvertFrom-Json
\\$map = @{}
\\$zhCards.PSObject.Properties | ForEach-Object {
    \\$key = \\$_.Name
    \\$value = \\$_.Value
    if \(\\$key -match '\\.title$'\) {
        \\$map[\\$value] = \\$key -replace '^CHARMOD-', '' -replace '\\.title$', ''
    }
}
Write-Host '=== Files NOT in localization map ==='
foreach \(\\$f in \\$files\) {
    \\$baseName = [System.IO.Path]::GetFileNameWithoutExtension\(\\$f.Name\)
    if \(-not \\$map.ContainsKey\(\\$baseName\)\) {
        Write-Host \\"RAW: [\\$\(\\$f.Name\)]\\"
        Write-Host \\"Base: [\\$baseName]\\"
        Write-Host '---'
    }
}
")

