Bash(powershell -Command "
Add-Type -AssemblyName System.Drawing
\\$bigDir = 'D:\\aMyGameSelf\\ModMaker\\CharacterModTemplate\\CharMod\\images\\card_portraits\\big'
\\$files = Get-ChildItem \\$bigDir -Filter '*.png' | Sort-Object Name

\\$w1000 = @\(\)
\\$w500 = @\(\)
\\$other = @\(\)

foreach \(\\$f in \\$files\) {
    \\$img = [System.Drawing.Image]::FromFile\(\\$f.FullName\)
    if \(\\$img.Width -eq 1000 -and \\$img.Height -eq 760\) {
        \\$w1000 += \\$f.Name
    } elseif \(\\$img.Width -eq 500 -and \\$img.Height -eq 380\) {
        \\$w500 += \\$f.Name
    } else {
        \\$other += \(\\$f.Name + ' \(' + \\$img.Width + 'x' + \\$img.Height + '\)'\)
    }
    \\$img.Dispose\(\)
}

Write-Host '=== 1000x760 \(共' \\$w1000.Count '\) ==='
\\$w1000 | ForEach-Object { Write-Host '  ' \\$_ }
Write-Host ''
Write-Host '=== 500x380 \(共' \\$w500.Count '\) ==='
\\$w500 | ForEach-Object { Write-Host '  ' \\$_ }
if \(\\$other.Count -gt 0\) {
    Write-Host ''
    Write-Host '=== Other ==='
    \\$other | ForEach-Object { Write-Host '  ' \\$_ }
}
")
